package com.burpautoai.ui;

import java.awt.BorderLayout;
import java.awt.Color;
import java.awt.Component;
import java.awt.Font;
import java.awt.Insets;
import javax.swing.BorderFactory;
import javax.swing.JLabel;
import javax.swing.JPanel;
import javax.swing.JScrollPane;
import javax.swing.JTextArea;

public class HelpPanel
extends JPanel {
    private static final Color BG_BLACK = Color.WHITE;
    private static final Color TEXT_GREEN = new Color(33, 37, 41);
    private static final Color PANEL_DARK = new Color(245, 247, 250);
    private static final Color BORDER_GREEN = new Color(210, 214, 220);
    private static final Color INPUT_BG = Color.WHITE;

    public HelpPanel() {
        this.initUI();
    }

    private void initUI() {
        this.setLayout(new BorderLayout(10, 10));
        this.setBackground(BG_BLACK);
        this.setBorder(BorderFactory.createCompoundBorder(BorderFactory.createLineBorder(BORDER_GREEN, 2), BorderFactory.createEmptyBorder(15, 15, 15, 15)));
        JLabel titleLabel = new JLabel("\u5de5\u5177\u4f7f\u7528\u4ecb\u7ecd", 0);
        titleLabel.setForeground(TEXT_GREEN);
        titleLabel.setFont(new Font("\u5fae\u8f6f\u96c5\u9ed1", 1, 20));
        this.add((Component)titleLabel, "North");
        JTextArea helpText = new JTextArea();
        helpText.setBackground(INPUT_BG);
        helpText.setForeground(TEXT_GREEN);
        helpText.setCaretColor(TEXT_GREEN);
        helpText.setFont(new Font("\u5fae\u8f6f\u96c5\u9ed1", 0, 14));
        helpText.setEditable(false);
        helpText.setLineWrap(true);
        helpText.setWrapStyleWord(true);
        helpText.setMargin(new Insets(20, 20, 20, 20));
        String content = "\u3010AI-Scanner\u4ecb\u7ecd\u3011\n\nAI-Scanner\u662f\u4e00\u6b3e\u57fa\u4e8e\u5927\u8bed\u8a00\u6a21\u578b\u7684\u4f01\u4e1a\u7ea7\u81ea\u52a8\u5316\u6e17\u900f\u6d4b\u8bd5\u5de5\u5177\uff0c\u901a\u8fc7\u6df1\u5ea6\u5b66\u4e60\u6280\u672f\u81ea\u52a8\u5206\u6790HTTP\u8bf7\u6c42\u7279\u5f81\uff0c\u667a\u80fd\u8bc6\u522b\u6f5c\u5728\u5b89\u5168\u6f0f\u6d1e\u7c7b\u578b\uff0c\u52a8\u6001\u751f\u6210\u9488\u5bf9\u6027\u6d4b\u8bd5\u8f7d\u8377\uff0c\u5229\u7528Burp Suite\u5185\u7f6e\u5f15\u64ce\u8fdb\u884c\u7cbe\u51c6\u6d4b\u8bd5\uff0c\u5e76\u901a\u8fc7AI\u4e8c\u6b21\u9a8c\u8bc1\u786e\u4fdd\u6f0f\u6d1e\u771f\u5b9e\u6027\uff08\u7f6e\u4fe1\u5ea6\u9608\u503c\u226590%\uff09\uff0c\u6700\u7ec8\u751f\u6210\u4e13\u4e1a\u7684\u6e17\u900f\u6d4b\u8bd5\u62a5\u544a\uff0c\u5b9e\u73b0\u4e86\u4ece\u6f0f\u6d1e\u53d1\u73b0\u5230\u9a8c\u8bc1\u518d\u5230\u62a5\u544a\u8f93\u51fa\u7684\u5168\u81ea\u52a8\u5316\u95ed\u73af\uff0c\u663e\u8457\u63d0\u5347\u5b89\u5168\u6d4b\u8bd5\u6548\u7387\u5e76\u964d\u4f4e\u8bef\u62a5\u7387\u3002\n\n========================================\n\n\u3010\u514d\u8d23\u58f0\u660e\u4e0e\u89c4\u8303\u3011\n\n1. \u6388\u6743\u8981\u6c42\n   \u672c\u5de5\u5177\u4ec5\u4f9b\u5408\u6cd5\u6388\u6743\u7684\u6e17\u900f\u6d4b\u8bd5\u4f7f\u7528\u3002\u4f7f\u7528\u8005\u5fc5\u987b\u5728\u6d4b\u8bd5\u524d\u83b7\u5f97\n   \u76ee\u6807\u7cfb\u7edf\u6240\u6709\u8005\u7684\u660e\u786e\u4e66\u9762\u6388\u6743\u3002\u672a\u7ecf\u6388\u6743\u5bf9\u8ba1\u7b97\u673a\u7cfb\u7edf\u8fdb\u884c\n   \u6e17\u900f\u6d4b\u8bd5\u5c5e\u4e8e\u8fdd\u6cd5\u884c\u4e3a\u3002\n\n2. \u6cd5\u5f8b\u8d23\u4efb\n   \u4f7f\u7528\u8005\u9700\u81ea\u884c\u627f\u62c5\u56e0\u4f7f\u7528\u672c\u5de5\u5177\u4ea7\u751f\u7684\u4e00\u5207\u6cd5\u5f8b\u8d23\u4efb\u3002\u5f00\u53d1\u8005\n   \u4e0d\u5bf9\u4efb\u4f55\u672a\u6388\u6743\u4f7f\u7528\u3001\u975e\u6cd5\u4f7f\u7528\u6216\u6ee5\u7528\u672c\u5de5\u5177\u7684\u884c\u4e3a\u627f\u62c5\u8d23\u4efb\u3002\n\n3. \u6d4b\u8bd5\u89c4\u8303\n   - \u5fc5\u987b\u9075\u5b88\u5f53\u5730\u6cd5\u5f8b\u6cd5\u89c4\u548c\u7f51\u7edc\u5b89\u5168\u6cd5\n   - \u5fc5\u987b\u5728\u6388\u6743\u8303\u56f4\u5185\u8fdb\u884c\u6d4b\u8bd5\n   - \u7981\u6b62\u5bf9\u672a\u6388\u6743\u76ee\u6807\u8fdb\u884c\u6d4b\u8bd5\n   - \u7981\u6b62\u4f7f\u7528\u672c\u5de5\u5177\u8fdb\u884c\u4efb\u4f55\u7834\u574f\u6027\u64cd\u4f5c\n   - \u53d1\u73b0\u6f0f\u6d1e\u540e\u5e94\u53ca\u65f6\u901a\u77e5\u76f8\u5173\u65b9\u4fee\u590d\n\n4. \u6570\u636e\u5b89\u5168\n   \u8bf7\u6c42\u548c\u54cd\u5e94\u6570\u636e\u4f1a\u53d1\u9001\u81f3AI\u670d\u52a1\u5546\u8fdb\u884c\u5206\u6790\uff0c\u8bf7\u6ce8\u610f\uff1a\n   - \u907f\u514d\u6d4b\u8bd5\u5305\u542b\u654f\u611f\u4fe1\u606f\u7684\u63a5\u53e3\n   - \u59a5\u5584\u4fdd\u7ba1API\u5bc6\u94a5\n   - \u4e86\u89e3\u5e76\u9075\u5b88AI\u670d\u52a1\u5546\u7684\u4f7f\u7528\u6761\u6b3e\n\n5. \u6210\u672c\u63a7\u5236\n   - AI\u5206\u6790\u4f1a\u6d88\u8017API Token\uff0c\u8bf7\u5408\u7406\u63a7\u5236\u6d4b\u8bd5\u8303\u56f4\n   - \u5efa\u8bae\u4f18\u5148\u6d4b\u8bd5\u5173\u952e\u63a5\u53e3\n   - \u907f\u514d\u91cd\u590d\u6d4b\u8bd5\u76f8\u540c\u63a5\u53e3\n\n========================================\n\n\u3010\u6838\u5fc3\u529f\u80fd\u3011\n\n1. AI\u667a\u80fd\u5206\u6790\n   - \u81ea\u52a8\u8bc6\u522b\u8bf7\u6c42\u4e2d\u53ef\u80fd\u5b58\u5728\u7684\u6f0f\u6d1e\u7c7b\u578b\n   - \u667a\u80fd\u751f\u6210\u9488\u5bf9\u6027\u7684\u6d4b\u8bd5\u8f7d\u8377\n   - \u8003\u8651WAF\u7ed5\u8fc7\u6280\u672f\n\n2. \u81ea\u52a8\u5316\u6d4b\u8bd5\n   - \u667a\u80fd\u53c2\u6570\u6ce8\u5165\uff08\u652f\u6301GET/POST/JSON\u7b49\uff09\n   - \u81ea\u52a8\u53d1\u9001\u6d4b\u8bd5\u8bf7\u6c42\n   - AI\u9a8c\u8bc1\u6f0f\u6d1e\u771f\u5b9e\u6027\uff08\u7f6e\u4fe1\u5ea6\u226590%\u624d\u62a5\u544a\uff09\n\n3. \u6df1\u5ea6\u6e17\u900f\n   - SQL\u6ce8\u5165\uff1a\u6d4b\u8bd5\u6570\u636e\u63d0\u53d6\u80fd\u529b\n   - XSS\uff1a\u6d4b\u8bd5\u591a\u79cd\u7f16\u7801\u7ed5\u8fc7\n   - RCE\uff1a\u6d4b\u8bd5\u547d\u4ee4\u6267\u884c\n\n4. \u4e13\u4e1a\u62a5\u544a\n   - AI\u751f\u6210\u8be6\u7ec6\u6f0f\u6d1e\u62a5\u544a\n   - \u5927\u767d\u8bdd\u89e3\u91ca\u6d4b\u8bd5\u8fc7\u7a0b\n   - \u652f\u6301\u5bfc\u51faHTML/MD\u683c\u5f0f\n\n========================================\n\n\u3010\u4f7f\u7528\u6b65\u9aa4\u3011\n\n\u7b2c\u4e00\u6b65\uff1a\u914d\u7f6eAI\n   1. \u70b9\u51fb\u53f3\u4e0a\u89d2\u300c\u6253\u5f00\u914d\u7f6e\u300d\u6309\u94ae\n   2. \u9009\u62e9AI\u670d\u52a1\u5546\uff08OpenAI/Anthropic/\u901a\u4e49\u5343\u95ee\u7b49\uff09\n   3. \u8f93\u5165\u4f60\u7684API Key\n   4. \u70b9\u51fb\u300c\u83b7\u53d6\u6a21\u578b\u300d\u6309\u94ae\n   5. \u9009\u62e9\u8981\u4f7f\u7528\u7684\u6a21\u578b\n   6. \u70b9\u51fb\u300c\u4fdd\u5b58\u914d\u7f6e\u300d\n   7. \u70b9\u51fb\u300c\u9a8c\u8bc1Key\u300d\u786e\u8ba4\n\n\u7b2c\u4e8c\u6b65\uff1a\u53d1\u9001\u6d4b\u8bd5\n   1. \u5728Burp Suite\u4efb\u4f55\u4f4d\u7f6e\uff08Proxy/Repeater/Target\u7b49\uff09\n   2. \u53f3\u952e\u70b9\u51fb\u8981\u6d4b\u8bd5\u7684HTTP\u8bf7\u6c42\n   3. \u9009\u62e9\u300c\u53d1\u9001\u5230 AI-Scanner\u300d\n   4. AI\u81ea\u52a8\u5f00\u59cb\u5206\u6790\u548c\u6d4b\u8bd5\n\n\u7b2c\u4e09\u6b65\uff1a\u67e5\u770b\u7ed3\u679c\n   1. \u5207\u6362\u5230\u300c\u4efb\u52a1\u5217\u8868\u300d\u6807\u7b7e\u67e5\u770b\u6240\u6709\u4efb\u52a1\n   2. \u70b9\u51fb\u4efb\u52a1\u67e5\u770b\u8be6\u7ec6\u4fe1\u606f\n   3. \u300c\u6f0f\u6d1e\u62a5\u544a\u300d\u6807\u7b7e\uff1a\u67e5\u770bAI\u751f\u6210\u7684\u8be6\u7ec6\u62a5\u544a\n   4. \u300c\u4efb\u52a1\u8be6\u60c5\u300d\u6807\u7b7e\uff1a\u67e5\u770b\u8bf7\u6c42\u548c\u54cd\u5e94\u5305\n   5. \u300c\u65e5\u5fd7\u7edf\u8ba1\u300d\u6807\u7b7e\uff1a\u67e5\u770b\u5b9e\u65f6\u65e5\u5fd7\u548c\u7edf\u8ba1\n\n\u7b2c\u56db\u6b65\uff1a\u5bfc\u51fa\u62a5\u544a\n   1. \u5728\u300c\u6f0f\u6d1e\u62a5\u544a\u300d\u6807\u7b7e\u70b9\u51fb\u5bfc\u51fa\u6309\u94ae\n   2. \u9009\u62e9HTML\u6216MD\u683c\u5f0f\n   3. \u4e5f\u53ef\u4ee5\u5728\u300c\u4efb\u52a1\u5217\u8868\u300d\u6279\u91cf\u5bfc\u51fa\u6240\u6709\u62a5\u544a\n\n========================================\n\n\u3010\u9ad8\u7ea7\u529f\u80fd\u3011\n\n- \u641c\u7d22\u548c\u7b5b\u9009\uff1a\u5728\u4efb\u52a1\u5217\u8868\u5feb\u901f\u627e\u5230\u76ee\u6807\u4efb\u52a1\n- \u53f3\u952e\u83dc\u5355\uff1a\u91cd\u65b0\u626b\u63cf\u3001\u5220\u9664\u4efb\u52a1\u3001\u590d\u5236URL\n- \u6279\u91cf\u64cd\u4f5c\uff1a\u6e05\u7a7a\u5df2\u5b8c\u6210\u4efb\u52a1\u3001\u6279\u91cf\u5bfc\u51fa\u62a5\u544a\n- \u7aef\u70b9\u7ba1\u7406\uff1a\u81ea\u5b9a\u4e49AI\u670d\u52a1\u5546\u914d\u7f6e\n\n========================================\n\n\u3010\u6ce8\u610f\u4e8b\u9879\u3011\n\n1. \u672c\u5de5\u5177\u4ec5\u4f9b\u6388\u6743\u6e17\u900f\u6d4b\u8bd5\u4f7f\u7528\n2. \u4f7f\u7528\u524d\u5fc5\u987b\u83b7\u5f97\u76ee\u6807\u7cfb\u7edf\u6240\u6709\u8005\u7684\u660e\u786e\u6388\u6743\n3. AI\u5206\u6790\u9700\u8981\u6d88\u8017API Token\n4. \u5efa\u8bae\u4f18\u5148\u6d4b\u8bd5\u5173\u952e\u63a5\u53e3\u4ee5\u8282\u7701\u6210\u672c\n5. \u7f6e\u4fe1\u5ea6\u226590%\u7684\u6f0f\u6d1e\u624d\u4f1a\u88ab\u62a5\u544a\uff0c\u786e\u4fdd\u4f4e\u8bef\u62a5\u7387\n\n========================================\n\n\u3010\u6280\u672f\u652f\u6301\u3011\n\n\u652f\u6301\u7684\u6f0f\u6d1e\u7c7b\u578b\uff1a\nSQL\u6ce8\u5165\u3001XSS\u3001RCE\u3001\u6587\u4ef6\u4e0a\u4f20\u3001SSRF\u3001XXE\u3001IDOR\u7b49\n\n\u652f\u6301\u7684AI\u670d\u52a1\uff1a\nOpenAI\u3001Anthropic\u3001\u901a\u4e49\u5343\u95ee\u3001\u6587\u5fc3\u4e00\u8a00\u3001\u667a\u8c31AI\u3001\nKimi\u3001DeepSeek\u7b4925+\u4e2a\u56fd\u5185\u5916\u4e3b\u6d41AI\u670d\u52a1\n\n========================================\n\n\u667a\u80fdAI\u6e17\u900f\u6d4b\u8bd5\u5de5\u5177 - \u8ba9\u5b89\u5168\u6d4b\u8bd5\u66f4\u667a\u80fd";
        helpText.setText(content);
        helpText.setCaretPosition(0);
        JScrollPane scrollPane = new JScrollPane(helpText);
        scrollPane.getViewport().setBackground(INPUT_BG);
        scrollPane.setBorder(BorderFactory.createLineBorder(BORDER_GREEN, 2));
        this.add((Component)scrollPane, "Center");
    }
}
